"""
Add fund.* i18n keys for the donation page across all ESRF locales that
do not yet ship a native translation. Before this script ran only en.json
and nl.json contained the fund.* tree, leaving 25 locales falling back to
English on fund.html. The script writes a quality translation tree per
locale, preserving the exact key shape used by fund.html so the data-i18n
attributes resolve cleanly. Bank/IBAN values are kept identical across
all locales — payment routing must not be translated.

Run:
  python3 scripts/add_fund_translations.py
"""
import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent
I18N = ROOT / "i18n"

