if __name__ == "__main__":
    en = json.loads((I18N / "en.json").read_text(encoding="utf-8"))
    en_fund = en["fund"]
    expected = set(en_fund.keys())

    written = 0
    for code, fund in T.items():
        path = I18N / f"{code}.json"
        data = json.loads(path.read_text(encoding="utf-8"))
        # Parity check
        missing = expected - set(fund.keys())
        if missing:
            raise SystemExit(f"{code}: missing keys {sorted(missing)}")
        extra = set(fund.keys()) - expected
        if extra:
            raise SystemExit(f"{code}: extra keys {sorted(extra)}")
        data["fund"] = fund
        path.write_text(
            json.dumps(data, ensure_ascii=False, indent=2) + "\n",
            encoding="utf-8",
        )
        written += 1
        print(f"  + {code}.json — fund.* added ({len(fund)} keys)")
    print(f"wrote fund translations to {written} locale files")
